import { Layout, Dropdown, Avatar, Button, Divider } from "antd";
import {
  MdMenu,
  MdOutlineLogout,
  MdOutlineAccountCircle,
} from "react-icons/md";
import { FaChevronDown } from "react-icons/fa";

import { useDispatch, useSelector } from "react-redux";
import { getColor, getFirstCharacter } from "../constants/avata.constant";
import { useNavigate } from "react-router-dom";
import { logout } from "../stores/slices/auth.slice";
import NotificationDropdown from "../pages/notifications/NotificationDropdown";
import { RiLockPasswordLine } from "react-icons/ri";
import { useTheme } from "../configs/useTheme";

const { Header } = Layout;

// Bell Icon SVG component
const BellIcon = () => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width="20"
    height="20"
    viewBox="0 0 24 24"
    fill="none"
    stroke="#6B7280"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
    style={{ cursor: "pointer" }}
  >
    <path d="M6 8a6 6 0 0 1 12 0c0 7 3 9 3 9H3s3-2 3-9" />
    <path d="M10.3 21a1.94 1.94 0 0 0 3.4 0" />
  </svg>
);

const AppHeader = () => {
  const { updateConfig } = useTheme();
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auths);

  const toggleSidebar = () => {
    const html = document.documentElement;

    html.classList.toggle("sidebar-enable");
    const isCondensed = html.getAttribute("data-sidenav-size") === "condensed";
    const newSize = isCondensed ? "default" : "condensed";

    html.setAttribute("data-sidenav-size", newSize);
    updateConfig("sidenav", { size: newSize });
  };

  // const toggleTheme = () => {
  //   updateConfig("theme", config.theme === "light" ? "dark" : "light");
  // };

  const userMenu = (
    <div className="dropdown-menu dropdown-menu-end show">
      {/* <div className="dropdown-header bg-primary mt-n3 rounded-top-2">
        <h6 className="text-overflow text-white m-0">Welcome !</h6>
      </div> */}
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/profile");
        }}
      >
        <MdOutlineAccountCircle className="me-2" /> <span>Profile</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item my-0"
        onClick={(e) => {
          e.preventDefault();
          navigate("/settings/change-password");
        }}
      >
        <RiLockPasswordLine className="me-2" /> <span>Đổi mật khẩu</span>
      </a>
      <Divider style={{ margin: 0 }} />
      <a
        href="#"
        className="dropdown-item notify-item"
        onClick={(e) => {
          e.preventDefault();
          navigate("/login");
          dispatch(logout());
        }}
      >
        <MdOutlineLogout className="me-2" /> <span>Đăng xuất</span>
      </a>
    </div>
  );

  return (
    <Header className="app-topbar bg-white shadow-sm px-3">
      <div className="page-container topbar-menu">
        {/* Left: hamburger toggle */}
        <div className="d-flex align-items-center gap-2">
          <Button
            type="text"
            className="sidenav-toggle-button px-2"
            icon={<MdMenu className="font-24" />}
            onClick={toggleSidebar}
          />
        </div>

        {/* Center: pill search bar */}
        <div className="topbar-search-wrapper">
          <div className="topbar-search-pill">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="15"
              height="15"
              viewBox="0 0 24 24"
              fill="none"
              stroke="#9CA3AF"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <circle cx="11" cy="11" r="8" />
              <path d="m21 21-4.35-4.35" />
            </svg>
            <input
              type="text"
              placeholder="Tìm kiếm..."
              className="topbar-search-input"
            />
          </div>
        </div>

        {/* Right: bell + admin profile */}
        <div className="d-flex align-items-center gap-3">
          {/* Bell notification */}
          <div className="topbar-item">
            <NotificationDropdown />
          </div>

          {user && (
            <div className="topbar-item nav-user">
              <Dropdown
                popupRender={() => userMenu}
                placement="bottomRight"
                trigger={["click"]}
              >
                <a
                  className="topbar-link dropdown-toggle drop-arrow-none px-2"
                  onClick={(e) => e.preventDefault()}
                >
                  <span className="topbar-admin-name">Admin</span>
                  {user.user?.image ? (
                    <Avatar src={user.user?.image} className="topbar-avatar" />
                  ) : (
                    <Avatar
                      className="topbar-avatar"
                      style={{
                        backgroundColor: getColor(
                          `${user.user?.first_name} ${user.user?.last_name}`
                        ),
                        color: "#fff",
                      }}
                    >
                      {getFirstCharacter(
                        `${user.user?.first_name} ${user.user?.last_name}`
                      )}
                    </Avatar>
                  )}
                </a>
              </Dropdown>
            </div>
          )}
        </div>
      </div>
    </Header>
  );
};

export default AppHeader;

import React from "react";
import { Select } from "antd";

const DashboardHeader = () => {
  return (
    <>
      {/* DASHBOARD CONTENT HEADER — title + filters + export on ONE row */}
      <div className="dashboard-content-header">
        <h1 className="dashboard-content-title">Dashboard</h1>

        <div className="dashboard-content-controls">
          <Select
            defaultValue="hanoi"
            style={{ width: 160 }}
            size="middle"
            options={[
              { value: "hanoi", label: "📍 Hà Nội" },
              { value: "hcm", label: "Hồ Chí Minh" },
              { value: "danang", label: "Đà Nẵng" },
            ]}
          />
          <Select
            defaultValue="t6t8"
            style={{ width: 150 }}
            size="middle"
            options={[
              { value: "t6t8", label: "T6 - T8/2026" },
              { value: "t1t3", label: "T1 - T3/2026" },
              { value: "t4t6", label: "T4 - T6/2026" },
              { value: "t9t12", label: "T9 - T12/2026" },
            ]}
          />
          <button className="export-btn" title="Xuất dữ liệu">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="18"
              height="18"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
              <polyline points="7 10 12 15 17 10" />
              <line x1="12" y1="15" x2="12" y2="3" />
            </svg>
          </button>
        </div>
      </div>
    </>
  );
};

export default DashboardHeader;

import React, { useState } from "react";
import { NavLink, useLocation } from "react-router-dom";
import { Badge } from "antd";
import {
  AiOutlineDashboard,
  AiOutlineUser,
  AiOutlineUsergroupAdd,
  AiOutlineCalendar,
  AiOutlineSchedule,
  AiOutlineShop,
  AiOutlineMoneyCollect,
  AiOutlineSwap,
  AiOutlineTeam,
  AiOutlineBell,
  AiOutlineSetting,
  AiOutlineQuestionCircle,
  AiOutlineLogout,
  AiOutlineMenu,
} from "react-icons/ai";
import { FiUsers, FiBookOpen } from "react-icons/fi";
import { BiBook, BiCalendarAlt } from "react-icons/bi";
import { BsCapslock, BsReceipt } from "react-icons/bs";

const menuGroups = [
  {
    title: "SETTINGS",
    items: [
      { label: "Dashboard", icon: <AiOutlineDashboard />, href: "/dashboard" },
      { label: "Học viên", icon: <AiOutlineUsergroupAdd />, href: "/students" },
      { label: "Giáo viên", icon: <AiOutlineUser />, href: "/teachers" },
      { label: "Quản lý lịch", icon: <AiOutlineCalendar />, href: "/schedules" },
      { label: "Kế hoạch thi", icon: <AiOutlineSchedule />, href: "/exam-plans" },
    ],
  },
  {
    title: "TÀI CHÍNH",
    items: [
      { label: "Sale", icon: <AiOutlineShop />, href: "/sales" },
      { label: "Các khoản thu chi", icon: <AiOutlineMoneyCollect />, href: "/payments" },
    ],
  },
  {
    title: "HỆ THỐNG",
    items: [
      { label: "Người dùng", icon: <FiUsers />, href: "/users" },
      { label: "Thông báo", icon: <AiOutlineBell />, href: "/notifications" },
      { label: "Hệ thống", icon: <AiOutlineSetting />, href: "/system" },
    ],
  },
];

const PhucAnSidebar = ({ collapsed, onToggle }) => {
  const { pathname } = useLocation();

  return (
    <div
      style={{
        width: collapsed ? "72px" : "240px",
        minHeight: "100vh",
        background: "#fff",
        borderRight: "1px solid #E5E7EB",
        display: "flex",
        flexDirection: "column",
        transition: "width 0.2s ease",
        position: "fixed",
        left: 0,
        top: 0,
        zIndex: 100,
        overflow: "hidden",
      }}
    >
      {/* Logo */}
      <div
        style={{
          padding: collapsed ? "20px 0" : "20px 20px",
          borderBottom: "1px solid #F3F4F6",
          display: "flex",
          alignItems: "center",
          gap: "10px",
          justifyContent: collapsed ? "center" : "flex-start",
          minHeight: "70px",
        }}
      >
        <div
          style={{
            width: 36,
            height: 36,
            borderRadius: 8,
            background: "linear-gradient(135deg, #F59E0B, #FBBF24)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontWeight: 800,
            fontSize: 15,
            color: "#fff",
            flexShrink: 0,
            letterSpacing: "-0.5px",
          }}
        >
          PA
        </div>
        {!collapsed && (
          <div>
            <div
              style={{
                fontWeight: 800,
                fontSize: 16,
                color: "#1F2937",
                letterSpacing: "0.5px",
                lineHeight: 1.2,
              }}
            >
              PHÚC AN
            </div>
            <div
              style={{
                fontSize: 10,
                color: "#9CA3AF",
                fontWeight: 500,
                letterSpacing: "1px",
                marginTop: 1,
              }}
            >
              TRUNG TÂM
            </div>
          </div>
        )}
      </div>

      {/* Menu */}
      <div style={{ flex: 1, overflowY: "auto", overflowX: "hidden", padding: "12px 0" }}>
        {menuGroups.map((group) => (
          <div key={group.title} style={{ marginBottom: "20px" }}>
            {!collapsed && (
              <div
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  color: "#9CA3AF",
                  letterSpacing: "1.5px",
                  padding: "0 20px",
                  marginBottom: "6px",
                }}
              >
                {group.title}
              </div>
            )}
            {group.items.map((item) => {
              const isActive = pathname === item.href || pathname.startsWith(item.href + "/");
              return (
                <div key={item.href}>
                  {collapsed ? (
                    <NavLink
                      to={item.href}
                      title={item.label}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        padding: "10px",
                        margin: "2px 8px",
                        borderRadius: 8,
                        color: isActive ? "#fff" : "#6B7280",
                        background: isActive ? "#1D4ED8" : "transparent",
                        fontSize: 18,
                        transition: "all 0.15s",
                        textDecoration: "none",
                      }}
                    >
                      <span style={{ color: isActive ? "#fff" : "#6B7280" }}>{item.icon}</span>
                    </NavLink>
                  ) : (
                    <NavLink
                      to={item.href}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        padding: "9px 20px",
                        margin: "1px 8px",
                        borderRadius: 8,
                        color: isActive ? "#fff" : "#4B5563",
                        background: isActive ? "#1D4ED8" : "transparent",
                        fontWeight: isActive ? 600 : 400,
                        fontSize: 13,
                        transition: "all 0.15s",
                        textDecoration: "none",
                      }}
                    >
                      <span style={{ fontSize: 16, flexShrink: 0, color: isActive ? "#fff" : "#6B7280" }}>{item.icon}</span>
                      <span>{item.label}</span>
                    </NavLink>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      {/* Bottom */}
      <div
        style={{
          borderTop: "1px solid #F3F4F6",
          padding: "12px 0",
        }}
      >
        {collapsed ? (
          <>
            <div
              title="Help"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "10px",
                margin: "2px 8px",
                borderRadius: 8,
                color: "#6B7280",
                cursor: "pointer",
                fontSize: 18,
              }}
            >
              <AiOutlineQuestionCircle />
            </div>
            <div
              title="Logout"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "10px",
                margin: "2px 8px",
                borderRadius: 8,
                color: "#EF4444",
                cursor: "pointer",
                fontSize: 18,
              }}
            >
              <AiOutlineLogout />
            </div>
          </>
        ) : (
          <>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "10px",
                padding: "9px 20px",
                margin: "1px 8px",
                borderRadius: 8,
                color: "#6B7280",
                cursor: "pointer",
                fontSize: 13,
              }}
            >
              <AiOutlineQuestionCircle style={{ fontSize: 16 }} />
              <span>Help</span>
            </div>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "10px",
                padding: "9px 20px",
                margin: "1px 8px",
                borderRadius: 8,
                color: "#EF4444",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 500,
              }}
            >
              <AiOutlineLogout style={{ fontSize: 16 }} />
              <span>Logout Account</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default PhucAnSidebar;

